export const query = graphql`
  query {
    servicios: allServiciosJson {
      nodes {
        title
        description
        href
        image {
          childImageSharp {
            gatsbyImageData(
                placeholder: BLURRED
                formats: [AUTO, WEBP, AVIF]
                width: 340
                height: 191
              )
          }
        }
      }
    }

    productos: allProductosJson {
      nodes {
        title
        description
        href
        image {
          childImageSharp {
            gatsbyImageData(
                placeholder: BLURRED
                formats: [AUTO, WEBP, AVIF]
                width: 340
                height: 191
              )
          }
        }
      }
    }
    backgroundImage: file(relativePath: { eq: "tonmix/2.jpeg" }) {
      childImageSharp {
        gatsbyImageData(placeholder: BLURRED, formats: [AUTO, WEBP, AVIF])
      }
    }
    allPagesJson(filter: { idPage: { eq: "index" } }) {
      nodes {
        idPage
        content {
          category
          description
          title
        }
      }
    }
  }
`

export default IndexPage
